static int num_threads = 1;

float euclid_dist_2(float *pt1, float *pt2, int numdims) {
    int i;
    float ans = 0.0f;
    for (i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

int find_nearest_point(float *pt, int nfeatures, float **pts, int npts) {
    int index = 0;
    int i;
    float min_dist = FLT_MAX;
    for (i = 0; i < npts; i++) {
        float dist = euclid_dist_2(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

float **kmeans_clustering(float **feature, int nfeatures, int npoints, int nclusters, float threshold, int *membership) {
    int i, j, k, n = 0, index, loop = 0;
    int *new_centers_len;
    float **new_centers;
    float **clusters;
    float delta;

    int **partial_new_centers_len;
    float ***partial_new_centers;
    int nthreads = num_threads;

    clusters = (float **)malloc(nclusters * sizeof(float *));
    if (!clusters) return NULL;
    clusters[0] = (float *)malloc(nclusters * nfeatures * sizeof(float));
    if (!clusters[0]) { free(clusters); return NULL; }
    for (i = 1; i < nclusters; i++) clusters[i] = clusters[i-1] + nfeatures;

    for (i = 0; i < nclusters; i++) {
        for (j = 0; j < nfeatures; j++) clusters[i][j] = feature[n][j];
        n++;
    }

    for (i = 0; i < npoints; i++) membership[i] = -1;

    new_centers_len = (int *)calloc(nclusters, sizeof(int));
    if (!new_centers_len) { free(clusters[0]); free(clusters); return NULL; }

    new_centers = (float **)malloc(nclusters * sizeof(float *));
    if (!new_centers) { free(new_centers_len); free(clusters[0]); free(clusters); return NULL; }
    new_centers[0] = (float *)calloc(nclusters * nfeatures, sizeof(float));
    if (!new_centers[0]) { free(new_centers); free(new_centers_len); free(clusters[0]); free(clusters); return NULL; }
    for (i = 1; i < nclusters; i++) new_centers[i] = new_centers[i-1] + nfeatures;

    partial_new_centers_len = (int **)malloc(nthreads * sizeof(int *));
    if (!partial_new_centers_len) { free(new_centers[0]); free(new_centers); free(new_centers_len); free(clusters[0]); free(clusters); return NULL; }
    partial_new_centers_len[0] = (int *)calloc(nthreads * nclusters, sizeof(int));
    if (!partial_new_centers_len[0]) { free(partial_new_centers_len); free(new_centers[0]); free(new_centers); free(new_centers_len); free(clusters[0]); free(clusters); return NULL; }
    for (i = 1; i < nthreads; i++) partial_new_centers_len[i] = partial_new_centers_len[i-1] + nclusters;

    partial_new_centers = (float **)malloc(nthreads * sizeof(float **));
    if (!partial_new_centers) { free(partial_new_centers_len[0]); free(partial_new_centers_len); free(new_centers[0]); free(new_centers); free(new_centers_len); free(clusters[0]); free(clusters); return NULL; }
    partial_new_centers[0] = (float **)malloc(nthreads * nclusters * sizeof(float *));
    if (!partial_new_centers[0]) { free(partial_new_centers); free(partial_new_centers_len[0]); free(partial_new_centers_len); free(new_centers[0]); free(new_centers); free(new_centers_len); free(clusters[0]); free(clusters); return NULL; }
    for (i = 1; i < nthreads; i++) partial_new_centers[i] = partial_new_centers[i-1] + nclusters;

    for (i = 0; i < nthreads; i++) {
        for (j = 0; j < nclusters; j++) {
            partial_new_centers[i][j] = (float *)calloc(nfeatures, sizeof(float));
            if (!partial_new_centers[i][j]) {
                for (int ii = 0; ii < nthreads; ii++) for (int jj = 0; jj < nclusters; jj++) if (partial_new_centers[ii][jj]) free(partial_new_centers[ii][jj]);
                free(partial_new_centers[0]); free(partial_new_centers); free(partial_new_centers_len[0]); free(partial_new_centers_len);
                free(new_centers[0]); free(new_centers); free(new_centers_len); free(clusters[0]); free(clusters);
                return NULL;
            }
        }
    }

    do {
        delta = 0.0f;
        for (i = 0; i < npoints; i++) {
            index = find_nearest_point(feature[i], nfeatures, clusters, nclusters);
            if (membership[i] != index) delta += 1.0f;
            membership[i] = index;
            int tid = 0;
            partial_new_centers_len[tid][index]++;
            for (j = 0; j < nfeatures; j++) partial_new_centers[tid][index][j] += feature[i][j];
        }

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nthreads; j++) {
                new_centers_len[i] += partial_new_centers_len[j][i];
                partial_new_centers_len[j][i] = 0;
                for (k = 0; k < nfeatures; k++) {
                    new_centers[i][k] += partial_new_centers[j][i][k];
                    partial_new_centers[j][i][k] = 0.0f;
                }
            }
        }

        for (i = 0; i < nclusters; i++) {
            for (j = 0; j < nfeatures; j++) {
                if (new_centers_len[i] > 0) clusters[i][j] = new_centers[i][j] / new_centers_len[i];
                new_centers[i][j] = 0.0f;
            }
            new_centers_len[i] = 0;
        }
    } while (delta > threshold && loop++ < 500);

    free(new_centers[0]); free(new_centers); free(new_centers_len);
    for (i = 0; i < nthreads; i++) for (j = 0; j < nclusters; j++) if (partial_new_centers[i][j]) free(partial_new_centers[i][j]);
    free(partial_new_centers[0]); free(partial_new_centers); free(partial_new_centers_len[0]); free(partial_new_centers_len);

    return clusters;
}

int cluster(int numObjects, int numAttributes, float **attributes, int nclusters, float threshold, float ***cluster_centres) {
    int *membership;
    float **tmp_cluster_centres;

    membership = (int *)malloc(numObjects * sizeof(int));
    if (!membership) return -1;

    tmp_cluster_centres = kmeans_clustering(attributes, numAttributes, numObjects, nclusters, threshold, membership);

    if (!tmp_cluster_centres) { free(membership); return -1; }

    if (*cluster_centres) {
        if ((*cluster_centres)[0]) free((*cluster_centres)[0]);
        free(*cluster_centres);
    }
    *cluster_centres = tmp_cluster_centres;

    free(membership);
    return 0;
}
